ALTER TABLE `telemetry_logs` ADD COLUMN `provider` String MATERIALIZED toString(attributes.gram.provider) COMMENT 'AI provider for the session account (e.g. anthropic, openai); set by ingest (materialized from attributes.gram.provider).';
ALTER TABLE `telemetry_logs` ADD COLUMN `external_org_id` String MATERIALIZED toString(attributes.gram.external_org_id) COMMENT 'Provider organization id for the account the user was logged into on-device (e.g. Claude organization.id). Distinct from the Gram org. Personal-account tracking discriminator; normalized by ingest (materialized from attributes.gram.external_org_id).';
ALTER TABLE `telemetry_logs` ADD COLUMN `account_type` String MATERIALIZED toString(attributes.gram.account_type) COMMENT 'team (company/enterprise account) or personal (individual account); set by ingest. Empty until classified (materialized from attributes.gram.account_type).';
ALTER TABLE `telemetry_logs` ADD INDEX `idx_telemetry_logs_mat_account_type` ((account_type)) TYPE set(0) GRANULARITY 4;
ALTER TABLE `telemetry_logs` ADD INDEX `idx_telemetry_logs_mat_external_org_id` ((external_org_id)) TYPE bloom_filter(0.01) GRANULARITY 1;
ALTER TABLE `telemetry_logs` ADD INDEX `idx_telemetry_logs_mat_provider` ((provider)) TYPE set(0) GRANULARITY 4;
